import{_ as o,o as a,c,a3 as i}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Module config:schema","description":"模块 config:schema 负责声明 Clore 工具链中核心配置数据结构的公共类型定义，包括 TaskConfig、LLMConfig 和 FilterRule。这些类型通过公开字段暴露了任务执行所需的所有配置项：路径配置（项目根目录、工作区根目录、输出根目录、编译命令数据库路径）、LLM 行为配置（系统提示、重试次数）以及文件过滤规则（包含/排除模式）。作为配置模块的数据合同，它独立于序列化或解析逻辑，仅定义结构体及其成员的可访问性，供配置加载、验证和消费方统一引用。","frontmatter":{"title":"Module config:schema","description":"模块 config:schema 负责声明 Clore 工具链中核心配置数据结构的公共类型定义，包括 TaskConfig、LLMConfig 和 FilterRule。这些类型通过公开字段暴露了任务执行所需的所有配置项：路径配置（项目根目录、工作区根目录、输出根目录、编译命令数据库路径）、LLM 行为配置（系统提示、重试次数）以及文件过滤规则（包含/排除模式）。作为配置模块的数据合同，它独立于序列化或解析逻辑，仅定义结构体及其成员的可访问性，供配置加载、验证和消费方统一引用。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/config/schema.md","filePath":"zh/clore/modules/config/schema.md"}'),r={name:"zh/clore/modules/config/schema.md"};function l(t,e,d,n,s,h){return a(),c("div",null,[...e[0]||(e[0]=[i('<h1 id="module-config-schema" tabindex="-1">Module <code>config:schema</code> <a class="header-anchor" href="#module-config-schema" aria-label="Permalink to &quot;Module `config:schema`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>模块 <code>config:schema</code> 负责声明 Clore 工具链中核心配置数据结构的公共类型定义，包括 <code>TaskConfig</code>、<code>LLMConfig</code> 和 <code>FilterRule</code>。这些类型通过公开字段暴露了任务执行所需的所有配置项：路径配置（项目根目录、工作区根目录、输出根目录、编译命令数据库路径）、LLM 行为配置（系统提示、重试次数）以及文件过滤规则（包含/排除模式）。作为配置模块的数据合同，它独立于序列化或解析逻辑，仅定义结构体及其成员的可访问性，供配置加载、验证和消费方统一引用。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><code>std</code></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./load"><code>config:load</code></a></li><li><a href="./normalize"><code>config:normalize</code></a></li><li><a href="./validate"><code>config:validate</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-config-filterrule" tabindex="-1"><code>clore::config::FilterRule</code> <a class="header-anchor" href="#clore-config-filterrule" aria-label="Permalink to &quot;`clore::config::FilterRule`&quot;">​</a></h3><p>Declaration: <code>config/schema.cppm:7</code></p><p>Definition: <code>config/schema.cppm:7</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p><code>clore::config::FilterRule</code> 的内部结构由两个公开的 <code>std::vector&lt;std::string&gt;</code> 成员 <code>include</code> 和 <code>exclude</code> 组成，分别代表允许匹配和拒绝匹配的模式集合。该结构本身未定义任何构造函数、赋值运算符或其他成员函数，因此其生命周期完全由默认的隐式构造和析构管理。核心的不变性假设是 <code>include</code> 与 <code>exclude</code> 列表在逻辑上互斥——即同一个模式不应同时出现在两个列表中——但结构体自身不强制执行这一约束，依赖外部调用方或解析逻辑来保证语义一致性。<code>include</code> 和 <code>exclude</code> 向量的添加、删除、遍历等操作均委托给 <code>std::vector</code> 的标准接口，无额外封装或检查。</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>Each member is independently mutable</li><li>No constraints between include and exclude lists</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>include</code></li><li><code>exclude</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to represent filter configurations</li><li>Lists can be populated by callers to define filtering behavior</li></ul><h3 id="clore-config-llmconfig" tabindex="-1"><code>clore::config::LLMConfig</code> <a class="header-anchor" href="#clore-config-llmconfig" aria-label="Permalink to &quot;`clore::config::LLMConfig`&quot;">​</a></h3><p>Declaration: <code>config/schema.cppm:12</code></p><p>Definition: <code>config/schema.cppm:12</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p><code>clore::config::LLMConfig</code> 是一个聚合类型，内部通过两个公有成员保存 LLM 调用的基本配置。<code>system_prompt</code> 字段为 <code>std::string</code> 类型，用于存储系统级提示词；<code>retry_limit</code> 字段为 <code>std::uint32_t</code> 类型，默认初始化为 <code>0</code>，表示不进行重试。作为实现层的数据载体，该结构体不提供自定义构造函数或校验逻辑，所有成员均为直接访问，使用者需在构造后自行保证 <code>retry_limit</code> 的非负性（已由无符号类型保证）以及 <code>system_prompt</code> 的有效性。</p><h4 id="invariants-1" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-1" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li><code>retry_limit</code> 初始化为0</li></ul><h4 id="key-members-1" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-1" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>system_prompt</code></li><li><code>retry_limit</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>作为配置对象传递给LLM接口</li><li>从配置文件中解析</li></ul><h3 id="clore-config-taskconfig" tabindex="-1"><code>clore::config::TaskConfig</code> <a class="header-anchor" href="#clore-config-taskconfig" aria-label="Permalink to &quot;`clore::config::TaskConfig`&quot;">​</a></h3><p>Declaration: <code>config/schema.cppm:17</code></p><p>Definition: <code>config/schema.cppm:17</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p>结构体 <code>clore::config::TaskConfig</code> 将所有任务级配置参数聚合为一个纯聚合类型，不定义自定义构造函数或成员函数。其成员包括四个 <code>std::string</code> 路径字段（<code>compile_commands_path</code>、<code>project_root</code>、<code>output_root</code> 和 <code>workspace_root</code>），分别指定编译命令数据库位置、项目根、输出根和工作区根；以及一个 <code>FilterRule</code> 实例 <code>filter</code> 和一个 <code>LLMConfig</code> 实例 <code>llm</code>，分别控制过滤规则与语言模型配置。该结构无显式不变量约束，所有成员均为公开，调用方负责在赋值后维护路径间的语义一致性（例如 <code>workspace_root</code> 应为 <code>project_root</code> 的子目录）。</p><h4 id="invariants-2" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-2" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>Paths are stored as <code>std::string</code>.</li><li><code>filter</code> is of type <code>FilterRule</code>.</li><li><code>llm</code> is of type <code>LLMConfig</code>.</li></ul><h4 id="key-members-2" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-2" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>compile_commands_path</code></li><li><code>project_root</code></li><li><code>output_root</code></li><li><code>workspace_root</code></li><li><code>filter</code></li><li><code>llm</code></li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used as a configuration container passed to task execution functions.</li><li>Aggregates directory paths and sub-configurations for filtering and LLM interaction.</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p><code>config:schema</code> 模块定义了配置层核心的数据类型，包括 <code>FilterRule</code>、<code>LLMConfig</code> 和 <code>TaskConfig</code>，所有字段均为公有访问，设计为纯值对象。该模块仅依赖标准库，内部层次平坦，没有进一步拆分或隐藏的实现细节；它作为 <code>config</code> 模块的一个分区，集中存放配置模式的实体定义，供其他分区或使用者直接引用。</p>',43)])])}const f=o(r,[["render",l]]);export{u as __pageData,f as default};
